/**
 * Nxcode SDK - Agent Module
 *
 * Provides AI agents with tool calling capabilities.
 * Agents can call backend endpoints as tools and maintain conversation history.
 */

import { SimpleSchema } from './ai';

// ==================== Types ====================

/**
 * Tool definition for an agent
 */
export interface AgentTool {
  /** Unique name for the tool */
  name: string;
  /** Description of what the tool does (shown to AI) */
  description: string;
  /** Parameter schema using simplified syntax */
  parameters?: { [key: string]: SimpleSchema };
  /** Backend endpoint to call (POST request) */
  endpoint: string;
}

/**
 * Options for creating an agent
 */
export interface AgentOptions {
  /** System instructions for the agent */
  instructions: string;
  /** Available tools */
  tools: AgentTool[];
  /** Model to use (default: 'fast') */
  model?: string;
  /** Maximum tool call steps per run (default: 10) */
  maxSteps?: number;
}

/**
 * Callbacks for agent.run()
 */
export interface AgentRunCallbacks {
  /** Called when agent decides to call a tool */
  onToolCall?: (name: string, params: Record<string, unknown>) => void;
  /** Called when tool returns a result */
  onToolResult?: (name: string, result: unknown) => void;
  /** Called on each step with thinking/reasoning */
  onThinking?: (thought: string) => void;
}

/**
 * Result of agent.run()
 */
export interface AgentResult {
  /** Final output text from the agent */
  output: string;
  /** Tool calls made during this run */
  toolCalls: Array<{
    name: string;
    params: Record<string, unknown>;
    result: unknown;
  }>;
  /** Total token usage */
  usage?: {
    inputTokens: number;
    outputTokens: number;
  };
}

// ==================== Internal Types ====================

interface ChatMessage {
  role: 'user' | 'assistant' | 'system' | 'model';
  content: string;
  parts?: Array<{
    text?: string;
    functionCall?: { name: string; args: Record<string, unknown> };
    functionResponse?: { name: string; response: unknown };
  }>;
}

interface GeminiTool {
  functionDeclarations: Array<{
    name: string;
    description: string;
    parameters?: {
      type: string;
      properties: Record<string, unknown>;
      required: string[];
    };
  }>;
}

// ==================== Helper Functions ====================

/**
 * Convert simple schema to JSON Schema format for Gemini
 */
function toJsonSchemaProperty(schema: SimpleSchema): Record<string, unknown> {
  if (schema === 'string') return { type: 'STRING' };
  if (schema === 'number') return { type: 'NUMBER' };
  if (schema === 'boolean') return { type: 'BOOLEAN' };

  if (Array.isArray(schema)) {
    return {
      type: 'ARRAY',
      items: toJsonSchemaProperty(schema[0]),
    };
  }

  if (typeof schema === 'object') {
    const properties: Record<string, unknown> = {};
    const required: string[] = [];
    for (const [key, value] of Object.entries(schema)) {
      properties[key] = toJsonSchemaProperty(value);
      required.push(key);
    }
    return { type: 'OBJECT', properties, required };
  }

  return { type: 'STRING' };
}

/**
 * Convert AgentTool to Gemini function declaration
 */
function toolToGeminiFunction(tool: AgentTool): GeminiTool['functionDeclarations'][0] {
  const declaration: GeminiTool['functionDeclarations'][0] = {
    name: tool.name,
    description: tool.description,
  };

  // Always include parameters object (even if empty) for Gemini compatibility
  const properties: Record<string, unknown> = {};
  const required: string[] = [];

  if (tool.parameters) {
    for (const [key, value] of Object.entries(tool.parameters)) {
      properties[key] = toJsonSchemaProperty(value);
      required.push(key);
    }
  }

  declaration.parameters = {
    type: 'OBJECT',
    properties,
    required,
  };

  return declaration;
}

// ==================== Agent Class ====================

export class Agent {
  private options: Required<AgentOptions>;
  private history: ChatMessage[] = [];
  private apiEndpoint: string;
  private appId: string;
  private getToken: () => string | null;

  constructor(
    options: AgentOptions,
    apiEndpoint: string,
    appId: string,
    getToken: () => string | null
  ) {
    this.options = {
      instructions: options.instructions,
      tools: options.tools,
      model: options.model || 'fast',
      maxSteps: options.maxSteps || 10,
    };
    this.apiEndpoint = apiEndpoint;
    this.appId = appId;
    this.getToken = getToken;
  }

  /**
   * Run the agent with user input
   */
  async run(input: string, callbacks?: AgentRunCallbacks): Promise<AgentResult> {
    const token = this.getToken();

    // Add user message to history
    this.history.push({ role: 'user', content: input });

    const toolCalls: AgentResult['toolCalls'] = [];
    let totalInputTokens = 0;
    let totalOutputTokens = 0;
    let steps = 0;

    // Agent loop
    while (steps < this.options.maxSteps) {
      steps++;

      // Call Gemini with tools
      const response = await this.callGemini(token || undefined);

      totalInputTokens += response.usage?.inputTokens || 0;
      totalOutputTokens += response.usage?.outputTokens || 0;

      // Check if AI wants to call a function
      const functionCall = response.functionCall;
      if (functionCall) {
        callbacks?.onToolCall?.(functionCall.name, functionCall.args);

        // Find the tool
        const tool = this.options.tools.find((t) => t.name === functionCall.name);
        if (!tool) {
          throw new Error(`Unknown tool: ${functionCall.name}`);
        }

        // Call the tool endpoint
        const result = await this.callTool(tool, functionCall.args, token || undefined);
        callbacks?.onToolResult?.(functionCall.name, result);

        // Record tool call
        toolCalls.push({
          name: functionCall.name,
          params: functionCall.args,
          result,
        });

        // Add function call and response to history using raw parts from Gemini
        this.history.push({
          role: 'model',
          content: '',
          parts: (response.rawParts as any) || [{ functionCall: { name: functionCall.name, args: functionCall.args } }],
        });
        this.history.push({
          role: 'user',
          content: '',
          parts: [{ functionResponse: { name: functionCall.name, response: result } }],
        });

        // Continue loop to let AI process the result
        continue;
      }

      // No function call - AI is done, return the text response
      const output = response.text || '';

      // Add assistant response to history
      this.history.push({ role: 'assistant', content: output });

      return {
        output,
        toolCalls,
        usage: {
          inputTokens: totalInputTokens,
          outputTokens: totalOutputTokens,
        },
      };
    }

    throw new Error(`Agent exceeded maximum steps (${this.options.maxSteps})`);
  }

  /**
   * Clear conversation history
   */
  reset(): void {
    this.history = [];
  }

  /**
   * Get current conversation history
   */
  getHistory(): ChatMessage[] {
    return [...this.history];
  }

  // ==================== Private Methods ====================

  private async callGemini(token?: string): Promise<{
    text?: string;
    functionCall?: { name: string; args: Record<string, unknown> };
    rawParts?: unknown[];
    usage?: { inputTokens: number; outputTokens: number };
  }> {
    // Build contents from history
    const contents = this.history.map((msg) => {
      if (msg.parts) {
        return {
          role: msg.role === 'assistant' ? 'model' : msg.role,
          parts: msg.parts,
        };
      }
      return {
        role: msg.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: msg.content }],
      };
    });

    // Build tools
    const tools: GeminiTool[] = [
      {
        functionDeclarations: this.options.tools.map(toolToGeminiFunction),
      },
    ];

    // Build request with tool config to encourage tool use
    const request = {
      contents,
      tools,
      toolConfig: {
        functionCallingConfig: {
          mode: 'AUTO', // Let model decide when to use tools
        },
      },
      systemInstruction: {
        parts: [{ text: this.options.instructions }],
      },
    };

    const response = await fetch(
      `${this.apiEndpoint}/api/ai-gateway/v1beta/models/${this.options.model}:generateContent`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-App-Id': this.appId,
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
        },
        body: JSON.stringify(request),
      }
    );

    if (!response.ok) {
      const error = await response.json().catch(() => ({}));
      throw new Error(error.detail || error.message || 'Agent API call failed');
    }

    const data = await response.json();

    // Parse response
    const candidate = data.candidates?.[0];
    const parts = candidate?.content?.parts || [];

    // Check for function call (support both camelCase and snake_case)
    for (const part of parts) {
      const funcCall = part.functionCall || part.function_call;
      if (funcCall) {
        return {
          functionCall: {
            name: funcCall.name,
            args: funcCall.args || {},
          },
          rawParts: parts, // Save raw parts including thought_signature
          usage: {
            inputTokens: data.usageMetadata?.promptTokenCount || 0,
            outputTokens: data.usageMetadata?.candidatesTokenCount || 0,
          },
        };
      }
    }

    // Return text response
    const text = parts.find((p: { text?: string }) => p.text)?.text || '';
    return {
      text,
      usage: {
        inputTokens: data.usageMetadata?.promptTokenCount || 0,
        outputTokens: data.usageMetadata?.candidatesTokenCount || 0,
      },
    };
  }

  private async callTool(
    tool: AgentTool,
    params: Record<string, unknown>,
    token?: string
  ): Promise<unknown> {
    // Build context to pass to tool
    const body = {
      ...params,
      _context: {
        agentId: this.options.instructions.slice(0, 20), // Simple ID
        stepIndex: this.history.length,
        previousTools: this.history
          .filter((m) => m.parts?.some((p) => p.functionResponse))
          .map((m) => {
            const fr = m.parts?.find((p) => p.functionResponse)?.functionResponse;
            return fr ? { name: fr.name, result: fr.response } : null;
          })
          .filter(Boolean),
      },
    };

    const response = await fetch(tool.endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(token ? { Authorization: `Bearer ${token}` } : {}),
      },
      body: JSON.stringify(body),
    });

    if (!response.ok) {
      const error = await response.text();
      return { error: `Tool call failed: ${error}` };
    }

    return response.json();
  }
}
