/**
 * Nxcode SDK - Payment Module
 */

import type { ChargeOptions, ChargeResult, Transaction } from './types';

export class NxcodePayment {
  private apiEndpoint: string;
  private appId: string;
  private getToken: () => string | null;

  constructor(
    apiEndpoint: string,
    appId: string,
    getToken: () => string | null
  ) {
    this.apiEndpoint = apiEndpoint;
    this.appId = appId;
    this.getToken = getToken;
  }

  /**
   * Process an in-app purchase
   *
   * @param options - Charge options
   * @returns Charge result with transaction details
   */
  async charge(options: ChargeOptions): Promise<ChargeResult> {
    const token = this.getToken();
    if (!token) {
      return {
        success: false,
        error: 'Not authenticated. Please login first.',
      };
    }

    try {
      const response = await fetch(`${this.apiEndpoint}/api/sdk/payment/charge`, {
        method: 'POST',
        headers: this.getHeaders(token),
        body: JSON.stringify({
          amount: options.amount,
          description: options.description,
          metadata: options.metadata,
        }),
      });

      if (!response.ok) {
        if (response.status === 401) {
          return {
            success: false,
            error: 'Session expired. Please login again.',
          };
        }
        if (response.status === 402) {
          return {
            success: false,
            error: 'Insufficient balance. Please top up.',
          };
        }

        const errorData = await response.json().catch(() => ({}));
        return {
          success: false,
          error: errorData.detail || 'Payment failed',
        };
      }

      const result = await response.json();
      return result;
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Payment failed',
      };
    }
  }

  /**
   * Get user's transaction history
   *
   * @param limit - Maximum number of transactions to return
   * @param offset - Pagination offset
   * @returns Array of transactions
   */
  async getTransactions(limit = 50, offset = 0): Promise<Transaction[]> {
    const token = this.getToken();
    if (!token) {
      throw new Error('Not authenticated. Please login first.');
    }

    const response = await fetch(
      `${this.apiEndpoint}/api/sdk/payment/transactions?limit=${limit}&offset=${offset}`,
      {
        headers: this.getHeaders(token),
      }
    );

    if (!response.ok) {
      if (response.status === 401) {
        throw new Error('Session expired. Please login again.');
      }
      throw new Error('Failed to fetch transactions');
    }

    const data = await response.json();
    return data.transactions;
  }

  // ==================== Private Methods ====================

  private getHeaders(token: string): HeadersInit {
    return {
      'Content-Type': 'application/json',
      'X-App-Id': this.appId,
      'Authorization': `Bearer ${token}`,
    };
  }
}
